const response = $input.first().json;
const content = JSON.parse(response.choices[0].message.content);

const outputs = [];
if (content.twitter_thread) {
  content.twitter_thread.forEach((tweet, i) => {
    outputs.push({ json: { platform: 'twitter', content: tweet, order: i + 1, type: 'thread' } });
  });
}
if (content.linkedin_post) {
  outputs.push({ json: { platform: 'linkedin', content: content.linkedin_post, type: 'post' } });
}
if (content.instagram_caption) {
  outputs.push({ json: { platform: 'instagram', content: content.instagram_caption, type: 'post' } });
}
if (content.email_subject) {
  outputs.push({ json: { platform: 'email', subjects: content.email_subject, type: 'subjects' } });
}
if (content.blog_outline) {
  outputs.push({ json: { platform: 'blog', outline: content.blog_outline, type: 'outline' } });
}
return outputs;
